const item = $input.first() || { json: {} };
return [{
  json: {
    ...item.json,
    api_base: 'http://localhost:8000/api/v1',
    n8n_base: 'http://localhost:5678/webhook',
    gemini_model: 'models/gemini-2.5-flash',
    temperature: 0.1,
    memory_limit: 10
  },
  binary: item.binary
}];

const root = $input.first().json;
const body = root.body || root;
const sessionId = body.session_id || 'default';
const mensaje = body.mensaje || body.pregunta || body.message || '';
const filename = body.filename || null;

if (!mensaje && !filename) throw new Error('mensaje o filename es requerido');

return [{
  json: {
    session_id: sessionId,
    input: `[SESSION_ID:${sessionId}] ${mensaje}${filename ? ' [ARCHIVO:' + filename + ']' : ''}`
  }
}];

const input = $input.item.json;
const pregunta = input.input || input.query || JSON.stringify(input);
const rawInput = typeof pregunta === 'string' ? pregunta : JSON.stringify(pregunta);

let sessionId = 'default';
const sessionMatch = rawInput.match(/\[SESSION_ID:([^\]]+)\]/);
if (sessionMatch) sessionId = sessionMatch[1];
const cleanPregunta = rawInput.replace(/\[SESSION_ID:[^\]]+\]\s*/, '').replace(/\[ARCHIVO:[^\]]+\]\s*/, '').trim();

const n8nBase = $('Config').first().json.n8n_base;

try {
  const response = await this.helpers.httpRequest({
    method: 'POST',
    url: n8nBase + '/chat-auditoria',
    body: {
      session_id: sessionId,
      pregunta: cleanPregunta
    },
    json: true,
    timeout: 30000
  });
  return response.respuesta || JSON.stringify(response);
} catch (error) {
  return 'Error al consultar documentos RAG: ' + error.message;
}

const input = $input.item.json;
const filename = input.input || input.query || 'documento.pdf';
const rawInput = typeof filename === 'string' ? filename : JSON.stringify(filename);

let sessionId = 'default';
const sessionMatch = rawInput.match(/\[SESSION_ID:([^\]]+)\]/);
if (sessionMatch) sessionId = sessionMatch[1];
const cleanFilename = rawInput.replace(/\[SESSION_ID:[^\]]+\]\s*/, '').replace(/\[ARCHIVO:[^\]]+\]\s*/, '').trim();

const n8nBase = $('Config').first().json.n8n_base;

try {
  const response = await this.helpers.httpRequest({
    method: 'POST',
    url: n8nBase + '/upload-evidence',
    body: {
      session_id: sessionId,
      filename: cleanFilename
    },
    json: true,
    timeout: 30000
  });
  return 'Evidencia procesada: ' + JSON.stringify(response);
} catch (error) {
  return 'Error al subir evidencia: ' + error.message;
}

const apiBase = $('Config').first().json.api_base;

try {
  const response = await this.helpers.httpRequest({
    method: 'GET',
    url: apiBase + '/rag-stores/',
    json: true,
    timeout: 10000
  });
  return 'Stores disponibles: ' + JSON.stringify(response);
} catch (error) {
  return 'Error al listar stores: ' + error.message;
}
